    private void Update()
    {
#if UNITY_EDITOR
        if (Input.GetKeyDown(KeyCode.F11))
        {
            TestMode = true;
        }
#endif
        if (StartedLoading)
        {
            loadingMonsters -= Time.deltaTime;
            if (loadingMonsters <= 0)
            {
                StartedLoading = false;
            }
        }

    }


