    public void LoginAccount(SkyMavisLogin.Root userInfo)
    {
        AccountManager.username = userInfo.userInfo.name;
        string displayName = string.IsNullOrEmpty(userInfo.userInfo.name) ? userInfo.userInfo.roninAddress : userInfo.userInfo.name;
        if (usernameText != null)
            usernameText.text = displayName;
        usernameTexts?.Where(x => x != null).ToList().ForEach(x => x.text = displayName);
        RunManagerSingleton.instance.user_wallet_address = userInfo.userInfo.addr;

        LoadAssets(userInfo.monsters, userInfo.lands);
    }

    public void LoginAccount(string userInfoResponse)
    {
        try
        {
            if (loggingIn)
            {
                return;
            }

            Debug.Log("User info 1: " + userInfoResponse);
            SkyMavisLogin.Root userInfo = JsonUtility.FromJson<SkyMavisLogin.Root>(userInfoResponse);
            loggingIn = true;
            AccountManager.username = userInfo.userInfo.name;
            string displayName = string.IsNullOrEmpty(userInfo.userInfo.name) ? userInfo.userInfo.roninAddress : userInfo.userInfo.name;
            if (usernameText != null)
                usernameText.text = displayName;
            usernameTexts?.Where(x => x != null).ToList().ForEach(x => x.text = displayName);
            RunManagerSingleton.instance.user_wallet_address = userInfo.userInfo.addr;

            PlayerPrefs.SetString(wallet, userInfoResponse);
            LoadAssets(userInfo.monsters, userInfo.lands);
        }
        catch (Exception ex)
        {
            Debug.Log("ON LOGIN" + ex.ToString());
            PlayerPrefs.SetString("Auth", "");
            SceneManager.LoadScene(0);
            Loading.instance.DisableLoading();
        }

    }

    public void AddNFTs(string userInfoResponse)
    {
        loadingMonsters = 5;
        Debug.Log("User info: " + userInfoResponse);

        SkyMavisLogin.Root userInfo = JsonUtility.FromJson<SkyMavisLogin.Root>(userInfoResponse);

        SkyMavisLogin.Root userInfoPrev = JsonUtility.FromJson<SkyMavisLogin.Root>(PlayerPrefs.GetString(wallet));

        bool repeatedLands = userInfoPrev.lands.ResultObject.items.Select(x => x.token_id)
            .Contains(userInfo.lands.ResultObject.items[0].token_id);
        userInfoPrev.monsters.ResultObject.items.AddRange(userInfo.monsters.ResultObject.items);
        if (userInfo.lands.ResultObject.items.Count != 0 && !repeatedLands)
            userInfoPrev.lands.ResultObject.items.AddRange(userInfo.lands.ResultObject.items);

        if (repeatedLands)
        {
            userInfo.lands = new SkyMavisLogin.NftsResponse();
        }
        PlayerPrefs.SetString(wallet, JsonUtility.ToJson(userInfoPrev));
        AddAssets(userInfo.monsters, userInfo.lands);
    }

    private void AddAssets(SkyMavisLogin.NftsResponse monstersResponse, SkyMavisLogin.NftsResponse landsResponse)
    {
        try
        {
            List<GetMonstersExample.Monster> monsters = new List<GetMonstersExample.Monster>();
            List<GetMonstersExample.Land> lands = new List<GetMonstersExample.Land>();

            foreach (var monstersInList in monstersResponse.ResultObject.items)
            {
                try
                {
                    if (monstersInList.symbol.ToUpper() == "MONSTER" && monstersInList.rawMetadata.genes != "0x0")
                    {
                        GetMonstersExample.Monster monster = new GetMonstersExample.Monster();

                        monster.genes = monstersInList.rawMetadata.genes;
                        monster.@class = monstersInList.rawMetadata.properties.@class;
                        monster.id = monstersInList.token_id.ToString();
                        monster.name = monstersInList.rawMetadata.name;
                        monster.birthDate = monstersInList.rawMetadata.properties.birthdate;
                        monster.newGenes = monstersInList.rawMetadata.genes;
                        monster.bodyShape = monstersInList.rawMetadata.properties.bodyshape;
                        monster.f2p = monstersInList.f2p;

                        monster.stats = MonsterGeneUtils.GetStatsByGenesAndMonsterClass(monster.genes, monster.monsterClass);

                        Debug.Log("Loading parts");
                        List<string> partsClasses = MonsterGeneUtils.GetMonsterPartsClasses(monster.genes);
                        Debug.Log("Loading abilities");
                        List<string> partsAbilities = MonsterGeneUtils.ParsePartIdsFromHex(monster.genes);

                        if (partsAbilities == null)
                            continue;

                        Debug.Log("Abilities loaded");

                        List<GetMonstersExample.Part> monsterParts = new List<GetMonstersExample.Part>();

                        GetMonstersExample.Part horn = new GetMonstersExample.Part(partsClasses[2],
                            monstersInList.rawMetadata.properties.horn_id, "horn", 0, false, partsAbilities[2]);
                        GetMonstersExample.Part tail = new GetMonstersExample.Part(partsClasses[5],
                            monstersInList.rawMetadata.properties.tail_id, "tail", 0, false, partsAbilities[5]);
                        GetMonstersExample.Part back = new GetMonstersExample.Part(partsClasses[4],
                            monstersInList.rawMetadata.properties.back_id, "back", 0, false, partsAbilities[4]);
                        GetMonstersExample.Part mouth = new GetMonstersExample.Part(partsClasses[3],
                            monstersInList.rawMetadata.properties.mouth_id, "mouth", 0, false, partsAbilities[3]);

                        monsterParts.Add(horn);
                        monsterParts.Add(tail);
                        monsterParts.Add(back);
                        monsterParts.Add(mouth);

                        monster.parts = monsterParts.ToArray();

                        monsters.Add(monster);
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError("Error loading NFT: " + e.Message + " NFT id: " + monstersInList.token_id + " NFT SYMBOL: " + monstersInList.symbol);
                    continue;
                }
            }

            foreach (var nft in landsResponse.ResultObject.items)
            {
                try
                {
                    if (nft.symbol.ToUpper() == "LAND")
                    {
                        GetMonstersExample.Land land = new GetMonstersExample.Land();

                        land.token_id = nft.token_id;
                        land.land_type = nft.rawMetadata.properties.land_type;
                        land.col = nft.rawMetadata.properties.col;
                        land.row = nft.rawMetadata.properties.row;
                        lands.Add(land);
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError("Error loading NFT: " + e.Message + " NFT id: " + nft.token_id + " NFT SYMBOL: " + nft.symbol);
                    continue;
                }
            }

            var resultMonstersList = userMonsters.results.ToList();
            resultMonstersList.AddRange(monsters);

            if (userLands != null)
            {
                var resultLandList = userLands.results.ToList();

                resultLandList.AddRange(lands);
                userLands.results = resultLandList.ToArray();
            }
            userMonsters.results = resultMonstersList.ToArray();

            foreach (var userMonstersResult in userMonsters.results)
            {
                userMonstersResult.LoadGraphicAssets();
            }

        }
        catch (System.Exception ex)
        {
            Debug.LogError("Error processing response: " + ex.Message);
        }
    }

